class Solution {
    public String solveEquation(String equation) {
        int left = 0, right = equation.length() - 1;
        while (equation.charAt(left) == ' ') left++;
        while (equation.charAt(right) == ' ') right--;
        String[] parts = equation.substring(left, right + 1).split("=");
        int x1 = 0, y1 = 0;
        for (String part : parts[0].split("[+-]")) {
            if (part.equals("x")) x1++;
            else y1 += Integer.parseInt(part);
        }
        for (String part : parts[1].split("[+-]")) {
            if (part.equals("x")) x1--;
            else y1 -= Integer.parseInt(part);
        }
        if (x1 == 0) return x1 == y1 ? "Infinite solutions" : "No solution";
        return "x=" + (y1 / x1);
    }
}
